import{_ as g,C as r,o as e,c as h,a5 as n,b as o,w as a,a as l,E as s,a4 as p}from"./chunks/framework.gGRxziV4.js";const _=JSON.parse('{"title":"六种Workflow模式","description":"","frontmatter":{},"headers":[],"relativePath":"04-多Agent架构/03-六种Workflow模式.md","filePath":"04-多Agent架构/03-六种Workflow模式.md","lastUpdated":1774181700000}'),c={name:"04-多Agent架构/03-六种Workflow模式.md"};function E(A,t,u,b,B,m){const i=r("Mermaid"),d=r("WorkflowExplorer");return e(),h("div",null,[t[2]||(t[2]=n(`<h1 id="六种workflow模式" tabindex="-1">六种Workflow模式 <a class="header-anchor" href="#六种workflow模式" aria-label="Permalink to &quot;六种Workflow模式&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 4 模块的第 3 章。</p></blockquote><p>从确定性到并行化的模式光谱——Chaining 用确定性结构对冲不确定性，Routing 分而治之，Sectioning 用成本换效率，Voting 用算力换确定性。</p><hr><h2 id="prompt-chaining" tabindex="-1">Prompt Chaining <a class="header-anchor" href="#prompt-chaining" aria-label="Permalink to &quot;Prompt Chaining&quot;">​</a></h2><p>用确定性结构对冲不确定性。将复杂任务拆解成一系列固定的步骤，每个步骤的输出作为下一个步骤的输入。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户查询 → [步骤1: 理解意图] → [步骤2: 检索信息] → [步骤3: 生成回答] → 输出</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>每个步骤是独立的 LLM 调用，有明确的输入输出格式。像工厂流水线——每个工位只做一件事，产品在流水线上依次通过。</p><p><strong>优势</strong>：流程可控可预测，每步可独立测试调试，中间结果可缓存复用。</p><p><strong>劣势</strong>：灵活性差，无法处理计划外的情况，某个步骤失败整个链断裂。</p><p><strong>适用场景</strong>：流程固定的标准化任务——文档处理、数据转换、格式化输出。</p><hr><h2 id="routing" tabindex="-1">Routing <a class="header-anchor" href="#routing" aria-label="Permalink to &quot;Routing&quot;">​</a></h2><p>分而治之的关注点分离。根据输入特征将请求路由到不同的处理路径。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户查询 → [路由器: 意图分类] → ┬→ [技术支持 Agent]</span></span>
<span class="line"><span>                                ├→ [销售咨询 Agent]</span></span>
<span class="line"><span>                                └→ [投诉处理 Agent]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>路由器本身是一个轻量 LLM 调用，只做分类不做处理。分类后将请求交给专门的 Agent 处理。</p><p><strong>优势</strong>：每个处理路径可以针对特定场景优化，资源不会浪费在无关处理上。</p><p><strong>劣势</strong>：路由器的分类准确率是瓶颈——分错了后面的处理全白费。</p><p><strong>适用场景</strong>：客服系统、多领域问答、有明确分类维度的场景。</p><hr><h2 id="sectioning" tabindex="-1">Sectioning <a class="header-anchor" href="#sectioning" aria-label="Permalink to &quot;Sectioning&quot;">​</a></h2><p>用成本换效率的并行结构。将输入分成多个独立部分，每个部分由独立的 Agent 并行处理，最后合并结果。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>长文档 → ┬→ [Agent 1: 摘要第1-3章]</span></span>
<span class="line"><span>         ├→ [Agent 2: 摘要第4-6章]</span></span>
<span class="line"><span>         └→ [Agent 3: 摘要第7-9章]</span></span>
<span class="line"><span>    → [合并: 生成完整摘要]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>优势</strong>：大幅降低延迟（并行处理），充分利用资源。</p><p><strong>劣势</strong>：部分之间可能有依赖关系，分割点选择不当会导致信息丢失，合并逻辑可能复杂。</p><p><strong>适用场景</strong>：可自然分割的任务——长文档摘要、批量数据处理、多文件代码审查。</p><hr><h2 id="voting" tabindex="-1">Voting <a class="header-anchor" href="#voting" aria-label="Permalink to &quot;Voting&quot;">​</a></h2><p>用算力换确定性的投票机制。同一个任务交给多个 Agent 独立处理，然后通过投票或合并策略选出最佳结果。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户查询 → ┬→ [Agent 1: 回答A]</span></span>
<span class="line"><span>           ├→ [Agent 2: 回答B]</span></span>
<span class="line"><span>           └→ [Agent 3: 回答A]</span></span>
<span class="line"><span>    → [投票: 回答A 胜出]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>优势</strong>：提高输出质量和可靠性，减少随机性带来的波动。</p><p><strong>劣势</strong>：成本是 N 倍（N 个 Agent 同时跑），延迟取决于最慢的那个。</p><p><strong>适用场景</strong>：高价值输出、需要高确定性的关键决策、对抗 LLM 随机性的场景。</p><hr><h2 id="模式对比" tabindex="-1">模式对比 <a class="header-anchor" href="#模式对比" aria-label="Permalink to &quot;模式对比&quot;">​</a></h2>`,35)),(e(),o(p,null,{default:a(()=>[s(i,{id:"mermaid-89",class:"mermaid",graph:"quadrantChart%0A%20%20%20%20title%20%E5%85%AD%E7%A7%8D%20Workflow%20%E6%A8%A1%E5%BC%8F%E5%AF%B9%E6%AF%94%0A%20%20%20%20x-axis%20%22%E7%81%B5%E6%B4%BB%E6%80%A7%E4%BD%8E%22%20--%3E%20%22%E7%81%B5%E6%B4%BB%E6%80%A7%E9%AB%98%22%0A%20%20%20%20y-axis%20%22%E6%88%90%E6%9C%AC%E4%BD%8E%22%20--%3E%20%22%E6%88%90%E6%9C%AC%E9%AB%98%22%0A%20%20%20%20quadrant-1%20%22%E9%AB%98%E6%88%90%E6%9C%AC%E9%AB%98%E7%81%B5%E6%B4%BB%22%0A%20%20%20%20quadrant-2%20%22%E9%AB%98%E6%88%90%E6%9C%AC%E4%BD%8E%E7%81%B5%E6%B4%BB%22%0A%20%20%20%20quadrant-3%20%22%E4%BD%8E%E6%88%90%E6%9C%AC%E4%BD%8E%E7%81%B5%E6%B4%BB%22%0A%20%20%20%20quadrant-4%20%22%E4%BD%8E%E6%88%90%E6%9C%AC%E9%AB%98%E7%81%B5%E6%B4%BB%22%0A%20%20%20%20%22Chaining%22%3A%20%5B0.15%2C%200.2%5D%0A%20%20%20%20%22Routing%22%3A%20%5B0.55%2C%200.35%5D%0A%20%20%20%20%22Sectioning%22%3A%20%5B0.6%2C%200.5%5D%0A%20%20%20%20%22Voting%22%3A%20%5B0.25%2C%200.85%5D%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[l(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=n('<blockquote><p>💡 <strong>图解：</strong> 没有最优模式——Chaining 最便宜最死板，Voting 最贵最可靠，选型取决于任务的灵活性和成本容忍度。</p></blockquote><table tabindex="0"><thead><tr><th>模式</th><th>核心思想</th><th>灵活性</th><th>成本</th><th>延迟</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>Chaining</strong></td><td>确定性流水线</td><td>低</td><td>低</td><td>串行</td><td>流程固定的标准任务</td></tr><tr><td><strong>Routing</strong></td><td>意图分类路由</td><td>中</td><td>中</td><td>取决于路径</td><td>多领域多场景</td></tr><tr><td><strong>Sectioning</strong></td><td>并行分割</td><td>中</td><td>中</td><td>并行低延迟</td><td>可分割的批量任务</td></tr><tr><td><strong>Voting</strong></td><td>多数表决</td><td>低</td><td>高</td><td>并行高可靠</td><td>高价值关键决策</td></tr></tbody></table><p>四种模式是确定性编排的基础。它们的共同特点是流程在执行前就已经确定——Agent 不需要做决策，只需要按预定流程执行。</p><hr><h2 id="选型指南" tabindex="-1">选型指南 <a class="header-anchor" href="#选型指南" aria-label="Permalink to &quot;选型指南&quot;">​</a></h2>',5)),(e(),o(p,null,{default:a(()=>[s(i,{id:"mermaid-208",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E9%80%89%E6%8B%A9%20Workflow%20%E6%A8%A1%E5%BC%8F%5D%20--%3E%20B%7B%E4%BB%BB%E5%8A%A1%E6%98%AF%E5%90%A6%E5%8F%AF%E5%88%86%E5%89%B2%EF%BC%9F%7D%0A%20%20%20%20B%20--%3E%7C%E6%98%AF%7C%20C%5BSectioning%5D%0A%20%20%20%20B%20--%3E%7C%E5%90%A6%7C%20D%7B%E8%BE%93%E5%85%A5%E6%98%AF%E5%90%A6%E9%9C%80%E8%A6%81%E5%88%86%E7%B1%BB%EF%BC%9F%7D%0A%20%20%20%20D%20--%3E%7C%E6%98%AF%7C%20E%5BRouting%5D%0A%20%20%20%20D%20--%3E%7C%E5%90%A6%7C%20F%7B%E8%BE%93%E5%87%BA%E8%B4%A8%E9%87%8F%E6%98%AF%E5%90%A6%E5%85%B3%E9%94%AE%EF%BC%9F%7D%0A%20%20%20%20F%20--%3E%7C%E6%98%AF%7C%20G%5BVoting%5D%0A%20%20%20%20F%20--%3E%7C%E5%90%A6%7C%20H%5BChaining%5D%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[l(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=n('<blockquote><p>💡 <strong>图解：</strong> 从 Chaining 开始——它最简单最可控，需要并行用 Sectioning，需要分类用 Routing，需要高可靠用 Voting。</p></blockquote><p>选择模式之前先问三个问题：</p><p><strong>任务是否可分割？</strong> 可以自然分成独立子任务 → Sectioning。不能 → 继续下一个问题。</p><p><strong>输入是否需要分类？</strong> 有明确的分类维度（意图、领域、类型）→ Routing。没有 → 继续。</p><p><strong>输出质量是否关键？</strong> 关键到需要多 Agent 验证 → Voting。不关键 → Chaining。</p><p>大多数情况下，从 Chaining 开始——它最简单最可控。需要并行化时用 Sectioning，需要分类时用 Routing，需要高可靠性时用 Voting。</p><hr><hr><h2 id="⚠️-常见错误" tabindex="-1">⚠️ 常见错误 <a class="header-anchor" href="#⚠️-常见错误" aria-label="Permalink to &quot;⚠️ 常见错误&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">❌ 错误做法</th><th style="text-align:left;">✅ 正确做法</th><th style="text-align:left;">为什么</th></tr></thead><tbody><tr><td style="text-align:left;">简单任务用 Orchestrator-Workers</td><td style="text-align:left;">简单任务用 Chaining 就够了</td><td style="text-align:left;">过度设计增加延迟和成本</td></tr><tr><td style="text-align:left;">需要并行的任务用 Chaining</td><td style="text-align:left;">用 Sectioning 或 Orchestrator-Workers</td><td style="text-align:left;">Chaining 是线性的，不支持并行</td></tr><tr><td style="text-align:left;">需要迭代打磨的任务只跑一遍</td><td style="text-align:left;">用 Evaluator-Optimizer 模式</td><td style="text-align:left;">质量需要多轮反馈</td></tr><tr><td style="text-align:left;">Voting 模式只投 1 票</td><td style="text-align:left;">至少投 3 票取多数</td><td style="text-align:left;">1 票等于没有投票机制</td></tr></tbody></table><hr><h2 id="🎮-交互式模式探索器" tabindex="-1">🎮 交互式模式探索器 <a class="header-anchor" href="#🎮-交互式模式探索器" aria-label="Permalink to &quot;🎮 交互式模式探索器&quot;">​</a></h2><p>点击不同模式标签，查看流程图、适用场景和优劣势：</p>',13)),s(d),t[5]||(t[5]=n('<hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>Chaining：确定性流水线，流程固定可预测</li><li>Routing：意图分类路由，路由器准确率是瓶颈</li><li>Sectioning：并行分割降低延迟，注意分割点和合并逻辑</li><li>Voting：多 Agent 独立处理投票选出最佳，成本 N 倍</li><li>选型三问：可分割？需分类？质量关键？</li></ul><hr><p><strong>上一章</strong>: <a href="./02-指挥官与工人.html">指挥官与工人</a> | <strong>下一章</strong>: <a href="./04-动态编排与迭代.html">动态编排与迭代</a></p>',5))])}const f=g(c,[["render",E]]);export{_ as __pageData,f as default};
